// Production service worker — caches all Blazor WASM assets for offline support.
// service-worker-assets.js is auto-generated by dotnet publish with asset hashes.
self.importScripts('./service-worker-assets.js');
self.addEventListener('install', event => event.waitUntil(onInstall(event)));
self.addEventListener('activate', event => event.waitUntil(onActivate(event)));
self.addEventListener('fetch', event => event.respondWith(onFetch(event)));

const cacheNamePrefix = 'offline-cache-';
const cacheName = `${cacheNamePrefix}${self.assetsManifest.version}`;
const offlineAssetsInclude = [/\.dll$/, /\.pdb$/, /\.wasm/, /\.html/, /\.js$/, /\.json$/, /\.css$/, /\.woff2?$/, /\.png$/, /\.jpe?g$/, /\.gif$/, /\.ico$/, /\.blat$/, /\.dat$/];
const offlineAssetsExclude = [/^service-worker\.js$/, /^manifest\.json$/, /^tenant\.json$/];

const base = '/';
const baseUrl = new URL(base, self.origin);

async function onInstall(event) {
    const assetsRequests = self.assetsManifest.assets
        .filter(asset => offlineAssetsInclude.some(p => p.test(asset.url)))
        .filter(asset => !offlineAssetsExclude.some(p => p.test(asset.url)))
        .map(asset => new Request(asset.url, { integrity: asset.hash, cache: 'no-cache' }));
    await caches.open(cacheName).then(cache => cache.addAll(assetsRequests));
}

async function onActivate(event) {
    const cacheKeys = await caches.keys();
    await Promise.all(
        cacheKeys
            .filter(key => key.startsWith(cacheNamePrefix) && key !== cacheName)
            .map(key => caches.delete(key))
    );
}

async function onFetch(event) {
    if (event.request.method !== 'GET') return fetch(event.request);

    const cache = await caches.open(cacheName);

    if (event.request.mode === 'navigate') {
        // Serve index.html for all navigation — enables SPA routing offline
        return (await cache.match('index.html')) || fetch(event.request);
    }

    // For API calls skip the cache entirely
    const url = new URL(event.request.url);
    if (!url.pathname.startsWith(baseUrl.pathname)) return fetch(event.request);

    return (await cache.match(event.request)) || fetch(event.request);
}
